; マップを開いた時に必ず実行されるスクリプト
[initial]

f.saveIsForbidden = false;

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="Maps are important. If you get stuck, check the map carefully."

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("power", 1)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Strength permanently increased by 1!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@delevent
@addevent num=4
@addevent num=5
@addevent num=6
@se f=kacha
@wait time=800
@se f=fence
@switchfence x=1 y=11 way=s mode=open
@switchfence x=3 y=11 way=s mode=open
@switchfence x=5 y=11 way=s mode=open
@switchfence x=7 y=11 way=s mode=open
@wait time=1000
@walk turn=e
@wait time=500
@notice text="The metal cages lining this passageway all opened at once! The monsters that had been trapped inside rushed out!"
@monster pos=1 name=サラマンダー
@monster pos=2 name=サラマンダー
@monster pos=3 name=サラマンダー
@monster pos=4 name=サラマンダー
@monster pos=5 name=サラマンダー
@callbattle escape=false

[eventoff]
